mod weight_validation {
    use super::*;
    use serde::de;

    // This function is called when serializing a `f64` weight.
    // It's a simple passthrough.
    pub fn serialize<S>(value: &f64, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
